import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate, Link } from 'react-router-dom';
import { LogIn, Mail, Lock, Loader2 } from 'lucide-react';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const imagenFondo = "https://res.cloudinary.com/dwpgncjgn/image/upload/v1771939326/Home_kwrrd2.png";

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      // --- LLAMADA REAL AL BACKEND ---
      const response = await fetch('http://localhost:5000/api/auth/login', { // AJUSTA ESTA URL
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ correo: email, password })
      });

      const data = await response.json();

      if (response.ok) {
        // data debe ser algo como: { token: "...", user: { nombre: "...", rol: "cliente" } }
        login(data); 
        navigate('/');
      } else {
        setError(data.message || 'Credenciales incorrectas');
      }
    } catch (err) {
      console.error("Error login:", err);
      setError('Error al conectar con el servidor.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={pageWrapper}>
      <div style={{ ...heroBackground, backgroundImage: `url(${imagenFondo})` }}>
        <div style={overlay}>
          <div style={loginCard}>
            <div style={headerStyle}>
              <div style={iconCircle}><LogIn size={28} color="#e67e22" /></div>
              <h2 style={titleStyle}>¡Bienvenido de nuevo!</h2>
              <p style={subtitleStyle}>Ingresá a tu cuenta para continuar</p>
            </div>

            {error && <div style={errorBadge}>{error}</div>}

            <form onSubmit={handleSubmit} style={formStyle}>
              <div style={inputGroup}>
                <label style={labelStyle}>Email</label>
                <div style={inputWrapper}>
                  <Mail size={18} color="#94a3b8" style={inputIcon} />
                  <input
                    type="email"
                    placeholder="tu@email.com"
                    style={inputStyle}
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    required
                  />
                </div>
              </div>

              <div style={inputGroup}>
                <label style={labelStyle}>Contraseña</label>
                <div style={inputWrapper}>
                  <Lock size={18} color="#94a3b8" style={inputIcon} />
                  <input
                    type="password"
                    placeholder="••••••••"
                    style={inputStyle}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </div>
              </div>

              <button type="submit" style={btnSubmit} disabled={loading}>
                {loading ? <Loader2 size={20} className="spinner" /> : 'Iniciar Sesión'}
              </button>
            </form>

            <div style={footerStyle}>
              ¿No tienes cuenta? <Link to="/registro" style={linkStyle}>Regístrate aquí</Link>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .spinner { animation: spin 1s linear infinite; }
        @keyframes spin { to { transform: rotate(360deg); } }
      `}</style>
    </div>
  );
};

// --- ESTILOS ---
const pageWrapper = { width: '100%', height: 'calc(100vh - 75px)', overflow: 'hidden' };
const heroBackground = { width: '100%', height: '100%', backgroundSize: 'cover', backgroundPosition: 'center', position: 'relative' };
const overlay = { position: 'absolute', inset: 0, backgroundColor: 'rgba(15, 23, 42, 0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', backdropFilter: 'blur(4px)' };
const loginCard = { background: 'white', padding: '40px', borderRadius: '24px', width: '100%', maxWidth: '420px', boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.2)', textAlign: 'center' };
const headerStyle = { marginBottom: '30px' };
const iconCircle = { width: '60px', height: '60px', background: 'rgba(230, 126, 34, 0.1)', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 15px' };
const titleStyle = { margin: '0', color: '#1e293b', fontSize: '1.5rem', fontWeight: 'bold' };
const subtitleStyle = { color: '#64748b', fontSize: '0.9rem', marginTop: '5px' };
const formStyle = { textAlign: 'left' };
const inputGroup = { marginBottom: '20px' };
const labelStyle = { display: 'block', marginBottom: '8px', fontSize: '0.85rem', fontWeight: 'bold', color: '#475569' };
const inputWrapper = { position: 'relative', display: 'flex', alignItems: 'center' };
const inputIcon = { position: 'absolute', left: '15px' };
const inputStyle = { width: '100%', padding: '12px 12px 12px 45px', borderRadius: '12px', border: '1px solid #e2e8f0', fontSize: '1rem', outline: 'none' };
const btnSubmit = { width: '100%', padding: '14px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', fontSize: '1rem', cursor: 'pointer', display: 'flex', justifyContent: 'center', marginTop: '10px' };
const errorBadge = { background: '#fee2e2', color: '#dc2626', padding: '10px', borderRadius: '10px', fontSize: '0.85rem', marginBottom: '20px', fontWeight: '500' };
const footerStyle = { marginTop: '25px', fontSize: '0.9rem', color: '#64748b' };
const linkStyle = { color: '#e67e22', fontWeight: 'bold', textDecoration: 'none' };

export default Login;
